mapper.select:
select s.*, c.course_name, u.real_name as artist_name, t.term_name, cl.name as class_name from performance_schedule s left join repertoire_info c on s.course_id = c.id left join sys_user u on s.artist_id = u.id left join cultural_season t on s.term_id = t.id left join venue_info cl on s.class_id = cl.id
and c.course_name like concat('%', #{courseName}, '%')
and s.artist_id = #{artistId}
and s.term_id = #{termId}
and s.class_id = #{classId}
and s.status = #{status}
order by s.id desc

mapper.update:
update performance_schedule
course_id = #{courseId}, term_id = #{termId}, artist_id = #{artistId}, class_id = #{classId}, classroom = #{classroom}, week_day = #{weekDay}, start_section = #{startSection}, end_section = #{endSection}, max_member_count = #{maxStudentCount}, selected_count = #{selectedCount}, status = #{status},
where id = #{id}
